import{_ as e,o as r,c as d,ag as a}from"./chunks/framework.DLWhSH9p.js";const g=JSON.parse('{"title":"AI Agents","description":"","frontmatter":{},"headers":[],"relativePath":"guide/agents.md","filePath":"guide/agents.md"}'),o={name:"guide/agents.md"};function s(n,t,i,c,l,h){return r(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="ai-agents" tabindex="-1">AI Agents <a class="header-anchor" href="#ai-agents" aria-label="Permalink to &quot;AI Agents&quot;">​</a></h1><p>CRAFT uses specialized AI agents that collaborate through the content pipeline. Each agent has a defined role, structured output format, and quality expectations. Agents are invoked via the Claude Agent SDK with full tool access (Read, Write, Edit, Bash, Glob, Grep, WebSearch, WebFetch).</p><h2 id="pipeline-agents" tabindex="-1">Pipeline Agents <a class="header-anchor" href="#pipeline-agents" aria-label="Permalink to &quot;Pipeline Agents&quot;">​</a></h2><p>These agents are directly wired into the 7-stage orchestration pipeline:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Pipeline Stage</th><th>Tools</th><th>Output</th></tr></thead><tbody><tr><td><strong>Researcher</strong></td><td>Research</td><td>Web search, file read/write</td><td><code>research.md</code> — sources, data, competitive analysis, unique angle</td></tr><tr><td><strong>Writer</strong></td><td>Script</td><td>File read/write</td><td><code>script.md</code> — screenplay in channel character voice</td></tr><tr><td><strong>Storyboarder</strong></td><td>Storyboard</td><td>File read/write</td><td><code>storyboard.md</code> — visual sequences, scene layouts, timing</td></tr><tr><td><strong>Asset Finder</strong></td><td>Assets</td><td>Web search, file tools</td><td>Downloads media resources to episode directory</td></tr><tr><td><strong>Producer</strong></td><td>Review (all stages)</td><td>Read-only</td><td>Structured JSON: score (1-10), pass/fail, feedback, upstream issues</td></tr></tbody></table><h2 id="support-agents" tabindex="-1">Support Agents <a class="header-anchor" href="#support-agents" aria-label="Permalink to &quot;Support Agents&quot;">​</a></h2><p>These agents handle tasks outside the main pipeline:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Role</th></tr></thead><tbody><tr><td><strong>Content Architect</strong></td><td>Episode structure and outline generation</td></tr><tr><td><strong>Brand Designer</strong></td><td>Visual branding and identity</td></tr><tr><td><strong>Trend Analyst</strong></td><td>Trend identification and scoring</td></tr><tr><td><strong>Channel Wizard</strong></td><td>Channel setup and onboarding</td></tr><tr><td><strong>Curator</strong></td><td>Content proposal evaluation</td></tr><tr><td><strong>Discovery</strong></td><td>YouTube trend discovery</td></tr><tr><td><strong>Idea Router</strong></td><td>Idea classification and channel routing</td></tr><tr><td><strong>Channel Strategist</strong></td><td>Long-form channel growth analysis</td></tr></tbody></table><h2 id="how-agents-execute" tabindex="-1">How Agents Execute <a class="header-anchor" href="#how-agents-execute" aria-label="Permalink to &quot;How Agents Execute&quot;">​</a></h2><ol><li>The <code>worker-orchestrate</code> service determines the next stage to run</li><li>It loads the agent definition from <code>app/agents/{name}.md</code></li><li>Builds a prompt with episode context (channel, episode dir, iteration, prior feedback)</li><li>Invokes the Claude Agent SDK with <code>--dangerously-skip-permissions</code> (agents run in Docker)</li><li>The agent reads the episode directory, does its work, writes artifacts</li><li>The orchestrator checks the result and runs the <strong>Producer</strong> for review</li></ol><h2 id="producer-review" tabindex="-1">Producer Review <a class="header-anchor" href="#producer-review" aria-label="Permalink to &quot;Producer Review&quot;">​</a></h2><p>The Producer agent is the quality gate. After each stage, it:</p><ul><li>Reads the channel&#39;s <code>CHANNEL.md</code> for tone and audience expectations</li><li>Reads the stage output artifact</li><li>Scores 1-10 with structured JSON output</li><li>Provides actionable feedback if the score is below 7</li><li>Can flag <strong>upstream issues</strong> (e.g., &quot;the script is weak because the research missed X&quot;)</li></ul><p>The review uses the Agent SDK&#39;s <code>outputFormat: json_schema</code> for guaranteed structured output.</p><h2 id="budget-controls" tabindex="-1">Budget Controls <a class="header-anchor" href="#budget-controls" aria-label="Permalink to &quot;Budget Controls&quot;">​</a></h2><p>Each agent invocation has configurable budget limits:</p><table tabindex="0"><thead><tr><th>Stage</th><th>Max Turns</th><th>Budget</th><th>Review Budget</th></tr></thead><tbody><tr><td>Research</td><td>30</td><td>$2.00</td><td>$0.50</td></tr><tr><td>Script</td><td>30</td><td>$3.00</td><td>$0.50</td></tr><tr><td>Storyboard</td><td>25</td><td>$2.00</td><td>$0.50</td></tr><tr><td>Assets</td><td>30</td><td>$3.00</td><td>—</td></tr><tr><td>Final Review</td><td>15</td><td>$1.00</td><td>—</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Agent definitions live in <code>app/agents/*.md</code> — each file defines the agent&#39;s persona, instructions, and output expectations. Edit them to customize behavior.</p></div>',18)])])}const p=e(o,[["render",s]]);export{g as __pageData,p as default};
